    "ob-s1-body": "O ti ṣẹṣẹ ṣẹda akọọlẹ rẹ. Irin-ajo kukuru yii fihan ọ ibiti ohun gbogbo wa ati bii o ṣe le ni anfani julọ lati iriri ẹkọ rẹ.",
    "ob-s1-title": "Kaabo si Poly-Puff! 🎉",
    "ob-s2-body": "Ṣaaju ki o to bẹrẹ adaṣe, gba iṣẹju 2 lati pari profaili rẹ. Fi ede abinibi rẹ, ipele Gẹẹsi, iṣẹ, ati awọn ibi-afẹde ẹkọ rẹ kun. AI nlo eyi lati <strong style=\"color:#56f0c0\">ṣe adaṣe idaraya kọọkan</strong> fun ọ - ti o jẹ ki adaṣe munadoko pupọ sii.",
    "ob-s2-cta": "→ Lọ si Profaili",
    "ob-s2-skip": "Emi yoo ṣe rẹ nigbamii",
    "ob-s2-title": "Ni akọkọ: Pari Profaili Rẹ 👤",
    "ob-s3-body": "Oju-ewe yii ni ile-iṣẹ rẹ. Gbogbo modulu adaṣe kan wa ni ijinna kan tẹ - Translation Trainer, Girama, Ọrọ-ọrọ, Gbigbọ, Kikọ, ati siwaju sii. Fi aami-iwe kun ki o le ma wa ọna rẹ pada nigbagbogbo.",
    "ob-s3-title": "Ile-iṣẹ Ẹkọ Rẹ 🏠",
    "ob-s4-body": "Translation Trainer ni modulu akọkọ. AI fun ọ ni gbolohun ọrọ ni ede rẹ lati tumọ si Gẹẹsi, lẹhinna fun ọ ni <strong style=\"color:#7ee8fa\">esi girama ati ọrọ-ọrọ alaye</strong>. O ṣiṣẹ fun ipele kọọkan, lati A1 si C2.",
    "ob-s4-title": "Bẹrẹ Nibi: Translation Trainer ↔",
    "ob-s5-body": "Ṣawari gbogbo akopọ: <strong>Adaṣe Girama</strong>, <strong>Word Chunks</strong>, kaadi <strong>Ọrọ-ọrọ</strong>, <strong>Gbigbọ</strong>, ati <strong>Kikọ</strong>. Modulu kọọkan nlo esi ti AI ṣe alaye fun profaili ati ipele rẹ.",
    "ob-s5-title": "Awọn Modulu Adaṣe Diẹ Sii 📚",
    "ob-s6-body": "Tọpinpin awọn aami rẹ, awọn ila, ati ilọsiwaju ni <strong>Ilọsiwaju</strong>. <strong>Ipenija Ojoojumọ</strong> tọju ila kan - iṣootọ ni ọna iyara julọ si sisọ daradara. Igbaradi idanwo tun wa fun <strong>IELTS</strong>, <strong>TOEFL</strong>, ati <strong>CAE</strong>.",
    "ob-s6-title": "Ilọsiwaju & Ipenija Ojoojumọ 📊",
    "ob-s7-body": "Bẹrẹ nipa pari profaili rẹ, lẹhinna fo sinu Translation Trainer. Bi o ṣe n ṣe adaṣe siwaju sii, ni bẹẹ gbogbo rẹ ṣe di alaye siwaju sii. Orire!",
    "ob-s7-practice": "Bẹrẹ Adaṣe",
    "ob-s7-profile": "Pari Profaili",
    "ob-s7-title": "O ti ṣetan! 🚀",
